scwin.f_openPopUp = async function () {
  var args = new Array();
  args[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
  args[1] = ""; //수출입구분코드

  var opts = {
    id: "smpPop",
    popupName: "본선관리번호검색팝업",
    //  팝업 타이틀에 표시
    type: "browserPopup",
    // window popup , 해당 옵션이 없으면 layer popup pageFramePopup  browserPopup
    modal: true,
    width: 1240 //900
    ,

    height: 600 //400
  };

  //초기화처리.
  ed_cvsslMgntNo.setValue("");
  let rtnValues = await $c.win.openPopup($p, "/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", opts, args);
  if (rtnValues != null) {
    ed_cvsslMgntNo.setValue(rtnValues[0]); //본선관리번호
  }
};

//-------------------------------------------------------------------------
// 조회 - 본선관리번호를 조건으로 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  // 검색조건 필수 입력 체크
  if (ed_cvsslMgntNo.getValue().trim() == "") {
    // 본선관리번호
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["본선관리번호"]); // "@은(는) 필수 입력 항목입니다."
    ed_cvsslMgntNo.focus();
    return;
  }
  var condition = "";
  condition = "?carryingVesselManagementNumber=" + ed_cvsslMgntNo.getValue();
  sbm_retrieve.action = "/ds.op.wrkplan.stvwrkplan.RetrieveCarryingVesselWorkPlanCMD.do" + condition;
  //submit 처리.
  let objSubmit = await $c.sbm.execute($p, sbm_retrieve);
  if (objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_retrieve_submitdone();
  }
};
scwin.sbm_retrieve_submitdone = async function (e) {
  var rowCnt;

  /************************************************************************
  * for=ds_cvsslInfo event=OnLoadCompleted 시작.
  ************************************************************************/
  rowCnt = ds_cvsslInfo.getRowCount();
  if (rowCnt <= 0) {
    await $c.gus.cfAlertMsg($p, "미등록된 본선관리번호 입니다. 확인후 다시 입력해주세요");
    $c.gus.cfEnableObjects($p, [btn_01, btn_02, btn_03, btn_04, btn_05, btn_06, btn_07, btn_08, btn_11, btn_12, chb_hveqInputPlanYn]);
    scwin.f_DivHoldEachWorkPlanList();
    ed_cvsslMgntNo.setValue("");
    ed_cvsslMgntNo.focus();
  } else {
    //div 출력부문 호출
    scwin.f_DivHoldEachWorkPlanList();
  }
  /************************************************************************
  * for=ds_cvsslInfo event=OnLoadCompleted 끝.
  ************************************************************************/

  //gr_cVMBOLInformationDTOList(ds_cVMBOLInformationDTOList) row 가 존재하면 0번째 자동 포커스주기.
  rowCnt = ds_cVMBOLInformationDTOList.getRowCount();
  if (rowCnt > 0) {
    gr_cVMBOLInformationDTOList.setFocusedCell(0, "comm");
  }

  //gr_holdWrkPlan(ds_holdWorkPlan) row 가 존재하면 0번째 자동 포커스주기.
  rowCnt = ds_holdWorkPlan.getRowCount();
  if (rowCnt > 0) {
    gr_holdWrkPlan.setFocusedCell(0, "holdNo");
  }

  /************************************************************************
  * for=ds_wrkHoldInfo_303  event=OnLoadCompleted 시작.
  ************************************************************************/
  rowCnt = ds_wrkHoldInfo_303.getRowCount();
  if (rowCnt == 0) {
    if (ds_cvsslInfo.getCellData(0, "cnt") == "0") {
      $c.gus.cfEnableObjects($p, [btn_04, btn_05]);
    } else {
      $c.gus.cfDisableBtn($p, [btn_01, btn_02, btn_03, btn_04, btn_05, btn_06, btn_07, btn_08, btn_11, btn_12, chb_hveqInputPlanYn]);
    }
  } else {
    if (ds_cvsslInfo.getCellData(0, "cnt") == "0") {
      $c.gus.cfEnableObjects($p, [btn_01, btn_02, btn_03, btn_06, btn_07, btn_08, btn_11, btn_12, chb_hveqInputPlanYn]);
    } else {
      $c.gus.cfDisableBtn($p, [btn_01, btn_02, btn_03, btn_04, btn_05, btn_06, btn_07, btn_08, btn_11, btn_12, chb_hveqInputPlanYn]);
    }
  }
  /************************************************************************
  * for=ds_wrkHoldInfo_303  event=OnLoadCompleted 끝.
  ************************************************************************/

  //gr_wrkHold(ds_wrkHoldInfo_303) row 가 존재하면 0번째 자동 포커스주기.
  if (rowCnt > 0) {
    gr_wrkHold.setFocusedCell(0, "holdNo");
  }

  /************************************************************************
  * for=ds_wrkHoldInfo_301  event=OnLoadCompleted 시작.
  ************************************************************************/
  rowCnt = ds_wrkHoldInfo_301.getTotalRow();
  if (rowCnt > 0) {
    ds_wrkHoldInfo_301.clearFilter();
    scwin.ds_wrkHoldInfo_301_setFilter(ds_wrkHoldInfo_303.getRowPosition());
  }
  /************************************************************************
  * for=ds_wrkHoldInfo_301  event=OnLoadCompleted 시작.
  ************************************************************************/

  //필터 걸린 gr_wrkHoldInfo(ds_wrkHoldInfo_301) row 가 존재하면 0번째 자동 포커스주기.
  if (ds_wrkHoldInfo_301.getRowCount() > 0) {
    gr_wrkHoldInfo.setFocusedCell(0, "impExpClsCd");
  }

  /************************************************************************
  * for=ds_wrkHoldInfo_304  event=OnLoadCompleted 시작.
  ************************************************************************/
  //입력상태 세팅
  gr_wrkHoldInfo_304.setReadOnly("column", "hveqKndCd", true);
  gr_wrkHoldInfo_304.setReadOnly("column", "hveqNrmCd", true);
  rowCnt = ds_wrkHoldInfo_304.getTotalRow();
  if (rowCnt != 0) {
    ds_wrkHoldInfo_304.clearFilter();
    scwin.ds_wrkHoldInfo_304_setFilter(ds_wrkHoldInfo_304.getRowPosition());
  }
  ds_eqNrmCd.clearFilter();
  if (ds_eqNrmCd.getTotalRow() != 0) {
    if (ds_eqNrmCd.getCellData(0, "initFlag") != "Y") {
      ds_eqNrmCd.insertRow(0);
      ds_eqNrmCd.setCellData(0, "initFlag", "Y");
      ds_eqNrmCd.reform();
    }
  }
  /************************************************************************
  * for=ds_wrkHoldInfo_304  event=OnLoadCompleted 끝.
  ************************************************************************/

  //gr_wrkHoldInfo_304(ds_wrkHoldInfo_304) row 가 존재하면 0번째 자동 포커스주기.
  if (rowCnt > 0) {
    gr_wrkHoldInfo_304.setFocusedCell(0, "hveqKndCd");
  }

  //조회후 수출입코드와 코드 수정불가 하도록 
  scwin.ds_wrkHoldInfo_301_SetEditCondition();

  //인서트시에 addrow 선언(그리드와 연결 안된 dataset들)	  
  if (ds_cvsslInfo_op302.getRowCount() == 0) {
    ds_cvsslInfo_op302.insertRow(0);
    ds_cvsslInfo_op302.setRowPosition(0);

    //초기값 셋팅.
    ds_cvsslInfo_op302.setCellData(0, "wrkHoldCnt", "0");
    ds_cvsslInfo_op302.setCellData(0, "fixgCoInputYn", "0");
    ds_cvsslInfo_op302.setCellData(0, "cvsslFmanCnt", "0");
    ds_cvsslInfo_op302.setCellData(0, "groundFmanCnt", "0");
    ds_cvsslInfo_op302.setCellData(0, "servPstInputYn", "0");
  } else {
    ds_cvsslInfo_op302.setRowPosition(0);
  }
};

