scwin.f_setCondition = function () {
  var userStatus302 = 0;
  var userStatus303 = 0;
  if (ds_cvsslInfo_op302.getCellData(ds_cvsslInfo_op302.getRowPosition(), "cvsslMgntNo") == ds_cvsslInfo.getCellData(0, "cvsslMgntNo")) {
    userStatus302 = 3; //update				
  }

  //0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
  if (ds_wrkHoldInfo_303.getRowStatus(ds_wrkHoldInfo_303.getRowPosition()) == "R") {
    userStatus302 = 0; //nomal
    userStatus303 = 0;
    // if (ds_cvsslInfo_op302.getCellData(ds_cvsslInfo_op302.getRowPosition(),"cvsslMgntNo") == ds_cvsslInfo.getCellData(0,"cvsslMgntNo")) {	
    // 	userStatus302 = 3; //update				
    // }					
    if (ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "cvsslMgntNo") == ds_cvsslInfo.getCellData(0, "cvsslMgntNo") && ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo") == ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo")) {
      userStatus303 = 3; //update				
    }
    if (ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "cvsslMgntNo") != ds_cvsslInfo.getCellData(0, "cvsslMgntNo") || ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo") != ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo")) {
      userStatus303 = 1; //insert				
    }
  }
  if (ds_wrkHoldInfo_303.getRowStatus(ds_wrkHoldInfo_303.getRowPosition()) == "C") {
    userStatus302 = 1; //insert
    userStatus303 = 1;
    if (ds_cvsslInfo_op302.getCellData(0, "cvsslMgntNo") == ds_cvsslInfo.getCellData(0, "cvsslMgntNo")) {
      userStatus302 = 3; //update	
    }
    if (ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "cvsslMgntNo") == ds_cvsslInfo.getCellData(0, "cvsslMgntNo") && ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo") == ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo")) {
      userStatus303 = 3; //update			
    }
  }
  if (ds_wrkHoldInfo_303.getRowStatus(ds_wrkHoldInfo_303.getRowPosition()) == "U") {
    userStatus302 = 3; //update
    userStatus303 = 3;
  }

  //key값 설정 부분
  //ds_cvsslInfo_op302.UserStatus(ds_cvsslInfo_op302.getRowPosition()) = userStatus302;
  //ds_wrkHoldInfo_303.UserStatus(ds_wrkHoldInfo_303.getRowPosition()) = userStatus303;	
  var sState302 = "";
  if (userStatus302 == 0) {
    sState302 = "R";
  } else if (userStatus302 == 1) {
    sState302 = "C";
  } else if (userStatus302 == 3) {
    sState302 = "U";
  }
  var sState303 = "";
  if (userStatus303 == 0) {
    sState303 = "R";
  } else if (userStatus303 == 1) {
    sState303 = "C";
  } else if (userStatus303 == 3) {
    sState303 = "U";
  }
  ds_cvsslInfo_op302.modifyRowStatus(ds_cvsslInfo_op302.getRowPosition(), sState302);
  ds_wrkHoldInfo_303.modifyRowStatus(ds_wrkHoldInfo_303.getRowPosition(), sState303);
  ds_wrkHoldInfo_301.setIgnoreStatus(true);
  ds_cvsslInfo_op302.setIgnoreStatus(true);
  ds_wrkHoldInfo_303.setIgnoreStatus(true);
  ds_wrkHoldInfo_304.setIgnoreStatus(true);
  for (var i = 0; i < ds_wrkHoldInfo_301.getRowCount(); i++) {
    ds_wrkHoldInfo_301.setCellData(i, "cvsslMgntNo", ds_cvsslInfo.getCellData(0, "cvsslMgntNo"));
  }
  ds_wrkHoldInfo_301.setCellData(ds_wrkHoldInfo_301.getRowPosition(), "holdNo", ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo"));
  ds_cvsslInfo_op302.setCellData(ds_cvsslInfo_op302.getRowPosition(), "cvsslMgntNo", ds_cvsslInfo.getCellData(0, "cvsslMgntNo"));
  for (var i = 0; i < ds_wrkHoldInfo_303.getRowCount(); i++) {
    ds_wrkHoldInfo_303.setCellData(i, "cvsslMgntNo", ds_cvsslInfo.getCellData(0, "cvsslMgntNo"));
  }
  ds_wrkHoldInfo_303.setCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo", ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo"));
  for (var i = 0; i < ds_wrkHoldInfo_304.getRowCount(); i++) {
    ds_wrkHoldInfo_304.setCellData(i, "cvsslMgntNo", ds_cvsslInfo.getCellData(0, "cvsslMgntNo"));
  }
  ds_wrkHoldInfo_304.setCellData(ds_wrkHoldInfo_304.getRowPosition(), "holdNo", ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo"));
  ds_wrkHoldInfo_301.setIgnoreStatus(false);
  ds_cvsslInfo_op302.setIgnoreStatus(false);
  ds_wrkHoldInfo_303.setIgnoreStatus(false);
  ds_wrkHoldInfo_304.setIgnoreStatus(false);
};

//중기 DataSet key값 설정 및 입력상태 조정
scwin.f_ds_wrkHoldInfo_304_AddRow = async function () {
  if (ds_wrkHoldInfo_303.getRowCount() == 0) {
    await $c.win.alert($p, "먼저 작업Hold를 입력하십시요.");
    return;
  }
  if (ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo").trim() == "") {
    await $c.win.alert($p, "먼저 작업Hold를 입력하십시요.");
    gr_wrkHold.setFocusedCell(ds_wrkHoldInfo_303.getRowPosition(), "holdNo", true);
    return;
  }
  var nRow = ds_wrkHoldInfo_304.getRowCount();
  ds_wrkHoldInfo_304.insertRow(nRow);
  ds_wrkHoldInfo_304.setCellData(nRow, "cvsslMgntNo", ds_cvsslInfo.getCellData(0, "cvsslMgntNo"));
  ds_wrkHoldInfo_304.setCellData(nRow, "holdNo", ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo"));
  ds_wrkHoldInfo_304.setCellData(nRow, "cvsslEqYn", "0");
  ds_wrkHoldInfo_304.setCellData(nRow, "invsslInputShiftCnt", "0");
  ds_wrkHoldInfo_304.setCellData(nRow, "alngvsslInputShiftCnt", "0");
  ds_wrkHoldInfo_304.setCellData(nRow, "invsslInputHhCnt", "0");
  ds_wrkHoldInfo_304.setCellData(nRow, "alngvsslInputHhCnt", "0");
  gr_wrkHoldInfo_304.setReadOnly("cell", nRow, "hveqKndCd", false);
  gr_wrkHoldInfo_304.setReadOnly("cell", nRow, "hveqNrmCd", false);
  gr_wrkHoldInfo_304.setFocusedCell(nRow, scwin.gr_wrkHoldInfo_304_colIdx);
};

//ds_wrkHoldInfo_301 DataSet key값 설정 및 입력상태 조정
scwin.ds_wrkHoldInfo_301_SetEditCondition = function () {
  gr_wrkHoldInfo.setReadOnly("column", "impExpClsCd", true);
  gr_wrkHoldInfo.setReadOnly("column", "commCd", true);
  gr_wrkHoldInfo.setReadOnly("column", "commNm", true);
};
scwin.f_wrkHoldInfo_301_AddRow = async function () {
  if (ds_wrkHoldInfo_303.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["작업HOLD"]); // "@은(는) 필수 입력 항목입니다."
    scwin.f_holdInsert();
    return;
  }
  if (ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo").trim() == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["작업HOLD"]); // "@은(는) 필수 입력 항목입니다."
    ds_wrkHoldInfo_303.setCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo", "");
    gr_wrkHold.setFocusedCell(ds_wrkHoldInfo_303.getRowPosition(), "holdNo");
    return;
  }
  var nRow = ds_wrkHoldInfo_301.getRowCount();
  ds_wrkHoldInfo_301.insertRow(nRow);
  if (scwin.gr_wrkHoldInfoColIdx == undefined || scwin.gr_wrkHoldInfoColIdx == "") {
    scwin.gr_wrkHoldInfoColIdx = 0;
  }
  gr_wrkHoldInfo.setFocusedCell(nRow, scwin.gr_wrkHoldInfoColIdx);
  ds_wrkHoldInfo_301.setCellData(nRow, "cvsslMgntNo", ds_cvsslInfo.getCellData(0, "cvsslMgntNo"));
  ds_wrkHoldInfo_301.setCellData(nRow, "holdNo", ds_wrkHoldInfo_303.getCellData(ds_wrkHoldInfo_303.getRowPosition(), "holdNo"));
  if (ds_cvsslInfo.getCellData(0, "impPortcnt") != "" && ds_cvsslInfo.getCellData(0, "expPortcnt") != "") {
    gr_wrkHoldInfo.setReadOnly("cell", nRow, "impExpClsCd", false);
  } else if (ds_cvsslInfo.getCellData(0, "impPortcnt") != "" && ds_cvsslInfo.getCellData(0, "expPortcnt") == "") {
    ds_wrkHoldInfo_301.setCellData(nRow, "impExpClsCd", "I");
    gr_wrkHoldInfo.setReadOnly("cell", nRow, "impExpClsCd", true);
  } else if (ds_cvsslInfo.getCellData(0, "impPortcnt") == "" && ds_cvsslInfo.getCellData(0, "expPortcnt") != "") {
    ds_wrkHoldInfo_301.setCellData(nRow, "impExpClsCd", "O");
    gr_wrkHoldInfo.setReadOnly("cell", nRow, "impExpClsCd", true);
  }
  gr_wrkHoldInfo.setReadOnly("cell", nRow, "commCd", false);
  gr_wrkHoldInfo.setReadOnly("cell", nRow, "commNm", false);

  //행추가시 기본값 셋팅처리.
  ds_wrkHoldInfo_301.setCellData(nRow, "qty", 0);
  ds_wrkHoldInfo_301.setCellData(nRow, "wt", 0);
  ds_wrkHoldInfo_301.setCellData(nRow, "cbm", 0);
  ds_wrkHoldInfo_301.setCellData(nRow, "shiftPerWrkVol", 0);
};

