scwin.f_gridToExcel = async function (argGrid, argTitle) {
  // 검색조건
  var vDay = "본선관리번호 : " + ed_cvsslMgntNo.getValue();
  let colCount = 0;
  for (let i = 0; i < argGrid.getTotalCol(); i++) {
    if (argGrid.getColumnVisible(i) == true) {
      colCount++;
    }
  }
  let infoArr = [{
    rowIndex: 0,
    colIndex: 0,
    rowSpan: 1,
    colSpan: colCount,
    text: argTitle,
    textAlign: "center",
    fontSize: 16,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  }, {
    rowIndex: 2,
    colIndex: 0,
    rowSpan: 1,
    colSpan: colCount,
    text: vDay.replace(/:/g, '|').replace(/;/g, ''),
    textAlign: "left",
    fontSize: 10,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  }];
  const options = {
    fileName: argTitle + '.xlsx',
    sheetName: argTitle,
    startRowIndex: 3,
    startColumnIndex: 0,
    //type : "1",
    footerColor: '#D4DAE2',
    useStyle: true
  };
  await $c.data.downloadGridViewExcel($p, argGrid, options, infoArr);
};
