//for=gr_wrkHoldInfo event=OnPopup
scwin.gr_wrkHoldInfo_OnPopup = async function (rowIndex, colid, nowValue) {
  //기본적으로 필터링 걸린 부분이므로 필터리스트가 존재한다면 실 rowIdex 재 셋팅처리.
  if (ds_wrkHoldInfo_301.getFilterList().length > 0) {
    rowIndex = ds_wrkHoldInfo_301.getFilteredRowIndex(rowIndex);
  }
  switch (colid) {
    case "commNm":
      //그리드 인입후 onExit(onafteredit) 이벤트 처리다음에
      //본 이벤트가 바로 호출되므로 중복 호출되지않도록 핸들링처리.
      if (scwin.eventProNm == "" && scwin.eventProEndFlag == true) {
        await scwin.f_openCommPopUpGrid(udc_gr_wrkHoldInfo_commNm, 1, rowIndex, 'F');
      } else {
        scwin.interval02 = setInterval(async function () {
          if (scwin.eventProNm == "" && scwin.eventProEndFlag == true) {
            clearInterval(scwin.interval02);
            await scwin.f_openCommPopUpGrid(udc_gr_wrkHoldInfo_commNm, 1, rowIndex, 'F');
          }
        }, 100);
      }
      break;
    case "commCd":
      //그리드 인입후 onExit(onafteredit) 이벤트 처리다음에
      //본 이벤트가 바로 호출되므로 중복 호출되지않도록 핸들링처리.
      if (scwin.eventProNm == "" && scwin.eventProEndFlag == true) {
        await scwin.f_openCommPopUpGrid(udc_gr_wrkHoldInfo_commCd, 2, rowIndex, 'F');
      } else {
        scwin.interval02 = setInterval(async function () {
          if (scwin.eventProNm == "" && scwin.eventProEndFlag == true) {
            clearInterval(scwin.interval02);
            await scwin.f_openCommPopUpGrid(udc_gr_wrkHoldInfo_commCd, 2, rowIndex, 'F');
          }
        }, 100);
      }
      break;
  }
};

