scwin.gr_wrkHoldInfo_304_OnExit = async function (row, colid, olddata) {
  //중기 투입Shift수를 투입시간/8로 자동 세팅
  if (colid == "invsslInputHhCnt" && olddata != ds_wrkHoldInfo_304.getCellData(row, "invsslInputHhCnt")) {
    if (Number(ds_wrkHoldInfo_304.getCellData(row, colid)) == 0) {
      ds_wrkHoldInfo_304.setCellData(row, "invsslInputShiftCnt", 0);
    } else if (Number(ds_wrkHoldInfo_304.getCellData(row, colid)) > 0) {
      ds_wrkHoldInfo_304.setCellData(row, "invsslInputShiftCnt", Math.round(Number(ds_wrkHoldInfo_304.getCellData(row, colid)) / 8 * 10) / 10);
    }
  }
  if (colid == "alngvsslInputHhCnt" && olddata != ds_wrkHoldInfo_304.getCellData(row, "alngvsslInputHhCnt")) {
    if (Number(ds_wrkHoldInfo_304.getCellData(row, colid)) == 0) {
      ds_wrkHoldInfo_304.setCellData(row, "alngvsslInputShiftCnt", 0);
    } else if (Number(ds_wrkHoldInfo_304.getCellData(row, colid)) > 0) {
      ds_wrkHoldInfo_304.setCellData(row, "alngvsslInputShiftCnt", Math.round(Number(ds_wrkHoldInfo_304.getCellData(row, colid)) / 8 * 10) / 10);
    }
  }
  if (colid == "invsslInputShiftCnt" && olddata != ds_wrkHoldInfo_304.getCellData(row, "invsslInputShiftCnt")) {
    if (Number(ds_wrkHoldInfo_304.getCellData(row, colid)) < 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["투입시간(Shift수)"]);
      ds_wrkHoldInfo_304.setCellData(row, colid, olddata);
      return false;
    }
  }
  if (colid == "alngvsslInputShiftCnt" && olddata != ds_wrkHoldInfo_304.getCellData(row, "alngvsslInputShiftCnt")) {
    if (Number(ds_wrkHoldInfo_304.getCellData(row, colid)) < 0) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_007, ["투입시간(Shift수)"]);
      ds_wrkHoldInfo_304.setCellData(row, colid, olddata);
      return false;
    }
  }

  /***********************************************************************************
  * for=ds_wrkHoldInfo_304 event=OnColumnChanged 시작.
  ***********************************************************************************/
  if (colid == "hveqKndCd") {
    ds_eqNrmCd.clearFilter();
    ds_wrkHoldInfo_304.setCellData(row, "hveqNrmCd", "");
    if (ds_eqNrmCd.getRowCount() == 0) {
      ds_wrkHoldInfo_304.setCellData(row, "hveqNrmCd", " ");
    }
  } else if (colid == "hveqNrmCd") {
    ds_eqNrmCd.clearFilter();
    for (var i = 0; i < ds_wrkHoldInfo_304.getRowCount(); i++) {
      if (ds_wrkHoldInfo_304.getCellData(row, "holdNo") != "" && ds_wrkHoldInfo_304.getCellData(row, "holdNo") == ds_wrkHoldInfo_304.getCellData(i, "holdNo") && ds_wrkHoldInfo_304.getCellData(row, "hveqKndCd") == ds_wrkHoldInfo_304.getCellData(i, "hveqKndCd") && ds_wrkHoldInfo_304.getCellData(row, "hveqNrmCd") == ds_wrkHoldInfo_304.getCellData(i, "hveqNrmCd") && i != row) {
        await $c.gus.cfAlertMsg($p, "동일한 HOLD에 같은 중기종류의 규격을 계획할 수 없습니다.");
        if (ds_hveqKndCd.getCellData(0, "initFlag") == "") {
          ds_hveqKndCd.insertRow(0);
          ds_hveqKndCd.setCellData(0, "initFlag", "Y");
          ds_hveqKndCd.reform();
        }
        ds_wrkHoldInfo_304.setCellData(row, "hveqKndCd", "");
        if (ds_hveqKndCd.getCellData(0, "initFlag") == "Y") {
          ds_hveqKndCd.removeRow(0);
          ds_hveqKndCd.reform();
        }
        ds_wrkHoldInfo_304.setCellData(row, "hveqNrmCd", "");
        return;
      }
    }
  }
  /***********************************************************************************
  * for=ds_wrkHoldInfo_304 event=OnColumnChanged 끝.
  ***********************************************************************************/
};
