//(정수부+콤마) +소수부 혹은 (정수부+콤마) 표현
scwin.displayFormatter01 = function (val) {
  if (val == undefined || val == null || val == "") {
    return "";
  } else {
    //소수부 존재시
    if (val.indexOf(".") > -1) {
      let tempChar = val.split(".");
      var intStr = Number(tempChar[0]).toLocaleString();
      var sPrimeNum = tempChar[1];
      return intStr + "." + sPrimeNum;
    }
    //정수부만 존재시
    else {
      return Number(val).toLocaleString();
    }
  }
};

//(정수부+콤마) +소수부 혹은 (정수부+콤마) 표현.
//단 소수부 fix 가 3자리인경우에 사용.
scwin.displayFormatterFix03 = function (val) {
  if (val == undefined || val == null || val == "") {
    return "";
  } else {
    val = Number(val).toFixed(3);
    //소수부 존재시
    if (val.indexOf(".") > -1) {
      let tempChar = val.split(".");
      var intStr = Number(tempChar[0]).toLocaleString();
      var sPrimeNum = tempChar[1];
      return intStr + "." + sPrimeNum;
    }
    //정수부만 존재시
    else {
      return Number(val).toLocaleString();
    }
  }
};
scwin.inputTimeFormatter = function (val) {
  var sRtn = "";
  if (val != undefined && val != null && val != "") {
    if (val.length == 4) {
      sRtn = val.substr(0, 2) + ":" + val.substr(2, 2);
    } else {
      switch (val.length) {
        case 1:
          sRtn = val + " :  ";
          break;
        case 2:
          sRtn = val + ":  ";
          break;
        case 3:
          sRtn = val.substr(0, 2) + ":" + val.substr(2, 1) + " ";
          break;
      }
    }
  }
  return sRtn;
};
scwin.gr_wrkHoldInfo_304_hveqKndCd_setFormatter = function (data, formattedData, rowIndex, colIndex) {
  if (colIndex == 0) {
    var sRtn = formattedData;
    if (ds_wrkHoldInfo_304.getCellData(rowIndex, "hveqKndCd") == "" && formattedData.trim() == ":") {
      sRtn = "";
    }
    return sRtn;
  }
};
scwin.gr_wrkHoldInfo_304_hveqNrmCd_setFormatter = function (data, formattedData, rowIndex, colIndex) {
  if (colIndex == 1) {
    var sRtn = formattedData;
    if (ds_wrkHoldInfo_304.getCellData(rowIndex, "hveqNrmCd") == "" && formattedData.trim() == ":") {
      sRtn = "";
    }
    return sRtn;
  }
};
scwin.local_cfValidate_grid = async function (gridObj, option) {
  var sRtn = true;
  var colId;
  var colNm;
  var errMsg = "";
  let ds_obj = $p.getComponentById(gridObj.getDataList());
  for (var i = 0; i < ds_obj.getRowCount(); i++) {
    for (var j = 0; j < option.length; j++) {
      colId = option[j].split(":")[0];
      colNm = option[j].split(":")[1];
      if (ds_obj.getCellData(i, colId) == "") {
        sRtn = false;
        errMsg = gridObj.getUserData("gridName") + "의 " + (i + 1) + "번째 데이터에서 " + colNm + "은(는) 필수 입력 항목입니다.";
        await $c.gus.cfAlertMsg($p, errMsg);
        gridObj.setFocusedCell(i, colId);
        break;
      }
    }
  }
  return sRtn;
};
scwin.tbx_textbox1_onclick = async function (e) {
  //debugger;
};
scwin.ds_wrkHoldInfo_301_oncelldatachange = async function (info) {
  let row = info.rowIndex;
  let colid = info.colID;
  if (colid == "impExpClsCd" && ds_wrkHoldInfo_301.getCellData(row, "commCd") != "" || colid == "commCd" && ds_wrkHoldInfo_301.getCellData(row, "impExpClsCd") != "") {
    for (var i = 0; i < ds_wrkHoldInfo_301.getRowCount(); i++) {
      if (ds_wrkHoldInfo_301.getCellData(row, "commCd") == ds_wrkHoldInfo_301.getCellData(i, "commCd") && ds_wrkHoldInfo_301.getCellData(row, "holdNo") == ds_wrkHoldInfo_301.getCellData(i, "holdNo") && ds_wrkHoldInfo_301.getCellData(row, "impExpClsCd") == ds_wrkHoldInfo_301.getCellData(i, "impExpClsCd") && i != row) {
        await $c.gus.cfAlertMsg($p, "동일한 HOLD와 수출입구분에 같은 품목/품명을 계획할 수 없습니다.");
        ds_wrkHoldInfo_301.setCellData(row, "commCd", "");
        ds_wrkHoldInfo_301.setCellData(row, "commNm", "");
        return;
      }
    }
  }
};
